const body = typeof $json.body === 'string' ? JSON.parse($json.body) : $json.body;

const conversation_id = body.conversation_id || '';
const user = body.user || 'anonymous';

// Build the Dify API payload
return { json: {
  query: body.query || body.question || body.message || '',
  user: user,
  conversation_id: conversation_id,
  response_mode: 'blocking',
  inputs: body.inputs || {},
  // If it is a new conversation, leave conversation_id empty
}};

// Dify API requires specific headers
const apiKey = $env.DIFY_API_KEY;
if (!apiKey) throw new Error('DIFY_API_KEY environment variable not set');

$json._dify_headers = {
  'Authorization': 'Bearer ' + apiKey,
  'Content-Type': 'application/json'
};
$json._dify_url = ($env.DIFY_BASE_URL || 'https://api.dify.ai') + '/v1/chat-messages';

return { json: $json };

const difyResp = $input.first().json;

// Dify returns: { answer, conversation_id, id, metadata, ... }
const answer = difyResp.answer || difyResp.text || '';
const conversationId = difyResp.conversation_id || '';
const messageId = difyResp.id || '';

// Extract sources if Dify returned them
const retrieverResources = difyResp.metadata?.retriever_resources || [];
const sources = retrieverResources.map(r => ({
  doc: r.document_name || 'unknown',
  segment: r.segment_position || 0,
  content: (r.content || '').substring(0, 200)
}));

return {
  json: {
    answer: answer,
    conversation_id: conversationId,
    message_id: messageId,
    sources: sources,
    source_count: sources.length,
    timestamp: new Date().toISOString()
  }
};

const data = $input.first().json;

const response = {
  success: true,
  answer: data.answer || '(no answer from Dify)',
  conversation_id: data.conversation_id,
  sources: data.sources || [],
  source_count: data.source_count || 0,
  provider: 'dify-rag',
  timestamp: data.timestamp
};

return { json: response };

return {
  json: {
    success: false,
    error: 'Dify API call failed',
    status_code: $json.statusCode || 0,
    message: $json.message || JSON.stringify($json),
    fallback: true,
    timestamp: new Date().toISOString()
  }
};
